# eval_harness.py  — minimal iterative refinement harness
import json
import re
from anthropic import Anthropic

client = Anthropic()

# ── 1. Eval dataset ────────────────────────────────────────────────────────
EVAL_SET = [
    {
        "id": "e001",
        "input": "Extract the invoice number and total from: Invoice #INV-2024-0042, Total due: $1,234.56",
        "expected": {"invoice_number": "INV-2024-0042", "total_usd": 1234.56},
        "categories": ["format", "extraction"],
    },
    {
        "id": "e002",
        "input": "Extract the invoice number and total from: No. 7891, amount owed $99.00",
        "expected": {"invoice_number": "7891", "total_usd": 99.00},
        "categories": ["format", "extraction"],
    },
    {
        "id": "e003",
        "input": "Extract the invoice number and total from: Reference 2024/88, Amount: EUR 550",
        "expected": {"invoice_number": "2024/88", "total_usd": None},  # non-USD: null
        "categories": ["format", "edge-case"],
    },
]

# ── 2. Prompt versions ─────────────────────────────────────────────────────
PROMPT_V0 = """Extract the invoice number and total amount from the user message.
Return JSON: {"invoice_number": "...", "total_usd": <float or null>}"""

PROMPT_V1 = """Extract the invoice number and total amount from the user message.
Return ONLY valid JSON — no prose, no markdown fences — in exactly this shape:
{"invoice_number": "<string>", "total_usd": <float or null>}
Rules:
- total_usd must be a float if the currency is USD; null if currency is unknown or non-USD.
- invoice_number must be the raw identifier string, no labels."""

# ── 3. Runner ──────────────────────────────────────────────────────────────
def run_prompt(system_prompt: str, user_input: str) -> str:
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        system=system_prompt,
        messages=[{"role": "user", "content": user_input}],
    )
    return response.content[0].text.strip()

# ── 4. Scorer ─────────────────────────────────────────────────────────────
def score_case(actual_text: str, expected: dict) -> dict:
    """Returns {"pass": bool, "failure_category": str | None, "detail": str}"""
    try:
        actual = json.loads(actual_text)
    except json.JSONDecodeError:
        return {"pass": False, "failure_category": "FORMAT", "detail": "JSONDecodeError"}

    errors = []
    for key, exp_val in expected.items():
        act_val = actual.get(key)
        if exp_val is None and act_val is not None:
            errors.append(f"{key}: expected null, got {act_val!r}")
        elif exp_val is not None and act_val != exp_val:
            errors.append(f"{key}: expected {exp_val!r}, got {act_val!r}")

    if errors:
        return {"pass": False, "failure_category": "EXTRACTION", "detail": "; ".join(errors)}
    return {"pass": True, "failure_category": None, "detail": "ok"}

# ── 5. Eval runner ─────────────────────────────────────────────────────────
def run_eval(prompt: str, label: str = "v?") -> dict:
    results = []
    for case in EVAL_SET:
        actual = run_prompt(prompt, case["input"])
        score = score_case(actual, case["expected"])
        results.append({**case, "actual": actual, **score})

    passes = sum(1 for r in results if r["pass"])
    total = len(results)
    accuracy = passes / total

    failure_counts = {}
    for r in results:
        if not r["pass"]:
            cat = r["failure_category"]
            failure_counts[cat] = failure_counts.get(cat, 0) + 1

    print(f"\n=== Eval: {label} ===")
    print(f"Accuracy: {passes}/{total} ({accuracy:.0%})")
    if failure_counts:
        print("Failure breakdown:", json.dumps(failure_counts, indent=2))
    for r in results:
        status = "PASS" if r["pass"] else f"FAIL [{r['failure_category']}]"
        print(f"  {r['id']}: {status} — {r['detail']}")

    return {"label": label, "accuracy": accuracy, "failures": failure_counts}

# ── 6. Run both versions ───────────────────────────────────────────────────
if __name__ == "__main__":
    baseline = run_eval(PROMPT_V0, label="v0-baseline")
    improved = run_eval(PROMPT_V1, label="v1-schema+rules")
    delta = improved["accuracy"] - baseline["accuracy"]
    print(f"\nAccuracy delta: {delta:+.0%}")

# WRONG: fragile scorer — passes even if output has extra garbage
def score_wrong(actual: str, expected: str) -> bool:
    return expected in actual  # "INV-42" in "Here is your INV-42 extracted!" → True

# RIGHT: parse and compare fields structurally
def score_right(actual: str, expected: dict) -> bool:
    try:
        parsed = json.loads(actual)
    except json.JSONDecodeError:
        return False
    return all(parsed.get(k) == v for k, v in expected.items())
